@CircuitBreaker(name = "inventoryService", fallbackMethod = "fallbackInventory")
public boolean checkStock(String productId) {
    // If this call fails 50% of the time, the circuit trips OPEN.
    return restTemplate.getForObject("http://INVENTORY/check/" + productId, Boolean.class);
}

public boolean fallbackInventory(String productId, Throwable t) {
    // Instantly return false without waiting for network timeout
    return false; 
}

public void processOrder(Order order) {
    inventoryClient.reserveStock(order); // Step 1
    try {
        paymentClient.charge(order);     // Step 2
    } catch (PaymentFailedException e) {
        // Step 2 failed! Execute Compensating Transaction for Step 1
        inventoryClient.releaseStock(order);
        orderRepository.markAsFailed(order.getId());
    }
}

