List<Event> history = eventStore.getEvents(accountId);
Account account = new Account(accountId);

// Replay history to recreate current state in memory
for (Event e : history) {
    if (e instanceof DepositEvent) account.add(e.getAmount());
    if (e instanceof WithdrawalEvent) account.subtract(e.getAmount());
}
return account;

@Retry(name = "paymentRetry", fallbackMethod = "paymentFailed")
@Bulkhead(name = "paymentBulkhead", type = Bulkhead.Type.THREADPOOL)
public void processPayment() {
    // If this fails, it retries automatically based on config.
    // The bulkhead ensures this method only uses up to a fixed number of threads.
    paymentClient.charge();
}

// Write-Through caching implementation
@Transactional
public Product updateProduct(Product product) {
    // 1. Update primary database
    Product saved = productRepository.save(product); 
    // 2. Synchronously update the distributed Redis cache
    redisTemplate.opsForValue().set("product:" + saved.getId(), saved); 
    return saved;
}
